            NSLog("%@", logMessage)
            print(logMessage)
            #else
            NSLog("%@", logMessage)
            #endif
        }
    }
    
    private func formatLogMessage(_ data: AnalyticsData) -> String {
        let timestamp = data.timestamp.formatted()
        let eventType = data.eventType.rawValue
        let userId = data.userId ?? "unknown"
        let userEmail = data.userEmail ?? "unknown"
        
        var message = "[\(timestamp)] [\(eventType)] [User:\(userId)] [Email:\(userEmail)]"
        
        if let payload = data.payload {
